from pathlib import Path
FILES = {'tools/validate_roblox_profile.py': '#!/usr/bin/env python3\nfrom __future__ import annotations\n\nimport hashlib\nimport json\nimport sys\nimport unittest\nfrom pathlib import Path\n\nROOT = Path(__file__).resolve().parents[1]\nPROFILE = ROOT / "skills" / "signal-core" / "profiles" / "roblox_studio"\nsys.path.insert(0, str(PROFILE.parent))\n\nfrom roblox_studio.capabilities import default_capabilities\nfrom roblox_studio.capability_graph import CapabilityGraph\nfrom roblox_studio.profile import VALIDATORS\nfrom roblox_studio.registries import default_engines\n\nREQUIRED = [\n    PROFILE / "__init__.py", PROFILE / "profile.py", PROFILE / "activation.py",\n    PROFILE / "task_state.py", PROFILE / "capabilities.py", PROFILE / "capability_graph.py",\n    PROFILE / "registries.py", PROFILE / "evidence_ledger.py", PROFILE / "context_knapsack.py",\n    PROFILE / "workflow.py", PROFILE / "validators.py", PROFILE / "telemetry.py",\n    PROFILE / "datamodel.py", PROFILE / "output_virtualization.py", PROFILE / "memory.py",\n    PROFILE / "scheduler.py", PROFILE / "adapters" / "simulated" / "__init__.py",\n    PROFILE / "adapters" / "transcript" / "__init__.py", PROFILE / "adapters" / "live" / "__init__.py",\n    ROOT / "benchmarks" / "roblox_profile_benchmark.py", ROOT / "tools" / "verify_claims.py",\n]\n\n\ndef main() -> int:\n    checks: list[tuple[str, bool, str]] = []\n    checks.append(("source_directory", PROFILE.is_dir(), str(PROFILE)))\n    checks.append(("required_files", all(path.is_file() for path in REQUIRED), "ordinary source files"))\n    forbidden_payload = list(ROOT.rglob("payload-*.b64")) + list(ROOT.rglob(".signalcore-direct"))\n    checks.append(("no_encoded_source_transport", not forbidden_payload, ",".join(map(str, forbidden_payload))))\n    specs = default_capabilities()\n    engines = default_engines(specs)\n    try:\n        CapabilityGraph(specs, engines=engines.engines, validators=VALIDATORS)\n        graph_ok = True\n    except Exception as exc:\n        graph_ok = False\n        graph_detail = repr(exc)\n    else:\n        graph_detail = "33 records with executable coverage metadata"\n    checks.append(("capability_graph", graph_ok and len(specs) == 33, graph_detail))\n    loader = unittest.TestLoader()\n    suite = loader.discover(str(ROOT / "tests" / "roblox_profile"))\n    checks.append(("generated_test_count", suite.countTestCases() > 0, str(suite.countTestCases())))\n    manifest = PROFILE / "MANIFEST.sha256"\n    manifest_ok = manifest.is_file()\n    if manifest_ok:\n        for line in manifest.read_text(encoding="utf-8").splitlines():\n            digest, relative = line.split("  ", 1)\n            path = PROFILE / relative\n            manifest_ok = path.is_file() and hashlib.sha256(path.read_bytes()).hexdigest() == digest\n            if not manifest_ok:\n                break\n    checks.append(("profile_manifest", manifest_ok, str(manifest)))\n    result = {"ok": all(item[1] for item in checks), "checks": [{"name": n, "passed": p, "detail": d} for n,p,d in checks]}\n    print(json.dumps(result, indent=2, sort_keys=True))\n    return 0 if result["ok"] else 2\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'tools/verify_claims.py': '#!/usr/bin/env python3\nfrom __future__ import annotations\n\nimport hashlib\nimport json\nimport os\nimport re\nimport sys\nimport unittest\nfrom pathlib import Path\nfrom urllib.parse import unquote\n\nROOT = Path(__file__).resolve().parents[1]\nCLAIMS = ROOT / "docs" / "claims" / "claims.json"\nREADME = ROOT / "README.md"\nPROFILE = ROOT / "skills" / "signal-core" / "profiles" / "roblox_studio"\n\n\ndef source_tree_hash() -> str:\n    hasher = hashlib.sha256()\n    paths: list[Path] = []\n    for base in (PROFILE, ROOT / "tests" / "roblox_profile"):\n        paths.extend(path for path in base.rglob("*") if path.is_file() and "__pycache__" not in path.parts and path.name != "MANIFEST.sha256")\n    paths.append(ROOT / "benchmarks" / "roblox_profile_benchmark.py")\n    for path in sorted(paths):\n        hasher.update(path.relative_to(ROOT).as_posix().encode("utf-8")); hasher.update(b"\\0")\n        hasher.update(path.read_bytes()); hasher.update(b"\\0")\n    return hasher.hexdigest()\n\n\ndef markdown_links(text: str) -> list[str]:\n    return [target for target in re.findall(r"\\[[^\\]]+\\]\\(([^)]+)\\)", text) if not target.startswith(("http://", "https://", "#", "mailto:"))]\n\n\ndef main() -> int:\n    registry = json.loads(CLAIMS.read_text(encoding="utf-8"))\n    readme_text = README.read_text(encoding="utf-8")\n    failures: list[str] = []\n    for target in markdown_links(readme_text):\n        clean = unquote(target.split("#", 1)[0])\n        if clean and not (ROOT / clean).exists():\n            failures.append(f"broken README link: {target}")\n    for claim in registry["claims"]:\n        marker = f"[claim:{claim[\'claim_id\']}]"\n        if marker not in readme_text:\n            failures.append(f"README marker missing: {claim[\'claim_id\']}")\n        for path in claim["source_paths"] + claim["artifact_paths"]:\n            if not (ROOT / path).exists():\n                failures.append(f"claim path missing: {claim[\'claim_id\']} -> {path}")\n        if claim["status"] not in {"IMPLEMENTED", "INTERNALLY_VERIFIED", "SIMULATED", "LIVE_INTEGRATION_VERIFIED", "PUBLICLY_BENCHMARKED", "INDEPENDENTLY_REPRODUCED", "PLANNED"}:\n            failures.append(f"invalid maturity label: {claim[\'claim_id\']}")\n    test_artifact = json.loads((ROOT / "benchmarks" / "results" / "roblox-profile" / "profile-tests.json").read_text(encoding="utf-8"))\n    actual_tests = unittest.TestLoader().discover(str(ROOT / "tests" / "roblox_profile")).countTestCases()\n    if test_artifact["tests_run"] != actual_tests:\n        failures.append(f"test count drift: artifact={test_artifact[\'tests_run\']} actual={actual_tests}")\n    benchmark = json.loads((ROOT / "benchmarks" / "results" / "roblox-profile" / "simulated-50.json").read_text(encoding="utf-8"))\n    current_hash = source_tree_hash()\n    if benchmark["source_tree_hash"] != current_hash:\n        failures.append("benchmark source_tree_hash mismatch")\n    expected_commit = registry["source_commit"]\n    if expected_commit == "WORKTREE" and os.environ.get("SIGNALCORE_ALLOW_WORKTREE") != "1":\n        failures.append("claim registry still uses WORKTREE source identity")\n    for artifact in (test_artifact, benchmark):\n        if artifact["source_commit"] != expected_commit:\n            failures.append("source commit mismatch between claims and artifacts")\n    if benchmark["mode"] != "simulated" or benchmark["maturity"] != "SIMULATED_VERIFIED":\n        failures.append("simulated benchmark labeling is invalid")\n    if benchmark.get("unsafe_execution") != 0:\n        failures.append("unsafe execution claim is not zero")\n    result = {"ok": not failures, "source_tree_hash": current_hash, "failures": failures, "claims": len(registry["claims"]), "tests": actual_tests}\n    print(json.dumps(result, indent=2, sort_keys=True))\n    return 0 if not failures else 2\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n'}
for relative, content in FILES.items():
    path=Path(relative)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding='utf-8')
